# Simplified from CPython asyncio/base_events.py
ntodo = len(self._ready)
for _ in range(ntodo):
    handle = self._ready.popleft()
    if not handle._cancelled:
        handle._run()

class OnNextTick:
    """Awaitable that yields to the event loop for exactly one tick."""
    def __await__(self):
        yield  # Bare yield — tells the Task to reschedule us immediately

async def demo():
    await OnNextTick()  # Suspends, other tasks can run, then resumes

class YieldToLoop:
    def __await__(self):
        yield  # Single yield; Task will re-schedule us via call_soon

async def example():
    # One yield to the event loop, then resumes
    await YieldToLoop()
